{"code": "import json

# Load the results from the file
with open('file_storage/functions.query_db:44.json', 'r') as f:
    results = json.load(f)

matching_books = results['matching_books']

# Format the output for better readability
formatted_books = []
for book in matching_books:
    # Parse author information if it's JSON string
    author_info = book['author']
    if isinstance(author_info, str) and author_info.startswith('{'):
        try:
            author_data = json.loads(author_info)
            author_name = author_data.get('name', 'Unknown Author')
        except:
            author_name = 'Unknown Author'
    elif author_info and author_info != 'None':
        author_name = str(author_info)
    else:
        author_name = 'Unknown Author'

    formatted_book = {
        'title': book['title'],
        'author': author_name,
        'average_rating': float(book['avg_rating']),
        'review_count': int(book['review_count']),
        'book_id': book['book_id']
    }
    formatted_books.append(formatted_book)

# Sort by review count (descending) then by title
formatted_books.sort(key=lambda x: (-x['review_count'], x['title']))

print('__RESULT__:')
print(json.dumps({
    'count': len(formatted_books),
    'books': formatted_books
}))"}

